svg.script:
//
  (function() {
    const tracker = document.getElementById('head-tracker');

    const PIVOT_X = 815;
    const PIVOT_Y = 372;
    const MAX_ROTATE = 15;
    const MAX_OFFSET = 10;

    let currentFactor = 0;
    let targetFactor  = 0;
    const EASE = 0.08;

    document.addEventListener('mousemove', function(e) {
      const norm = e.clientY / window.innerHeight;
      targetFactor = (0.5 - norm) * 2; // flipped: top = positive (head back), bottom = negative (head forward)
    });

    // ── Blink system ──────────────────────────────────────────────
    const leftEye  = document.getElementById('left-eye');
    const rightEye = document.getElementById('right-eye');

    // Eye centers for scaleY pivot
    const LEFT_EYE_CY  = 339;
    const RIGHT_EYE_CY = 347;

    function setEyeScale(scaleY) {
      leftEye.setAttribute('transform',
        'translate(0,' + (LEFT_EYE_CY * (1 - scaleY)) + ') scale(1,' + scaleY + ')');
      rightEye.setAttribute('transform',
        'translate(0,' + (RIGHT_EYE_CY * (1 - scaleY)) + ') scale(1,' + scaleY + ')');
    }

    function animateEyelid(from, to, duration, onDone) {
      const start = performance.now();
      function step(now) {
        const t = Math.min((now - start) / duration, 1);
        // ease-in for closing, ease-out for opening
        const eased = to < from
          ? t * t               // ease-in (snap shut)
          : 1 - (1 - t) * (1 - t); // ease-out (drift open)
        setEyeScale(from + (to - from) * eased);
        if (t < 1) requestAnimationFrame(step);
        else if (onDone) onDone();
      }
      requestAnimationFrame(step);
    }

    function doBlink(onDone) {
      animateEyelid(1, 0, 80, function() {       // close fast
        animateEyelid(0, 1, 130, onDone);         // open slower
      });
    }

    function doSlowBlink(onDone) {
      animateEyelid(1, 0, 220, function() {      // close lazy
        setTimeout(function() {
          animateEyelid(0, 1, 280, onDone);       // open even lazier
        }, 60);
      });
    }

    function scheduleNextBlink() {
      // Random interval 2.5s – 6s
      const delay = 2500 + Math.random() * 3500;
      setTimeout(function() {
        const roll = Math.random();
        if (roll < 0.15) {
          // Double blink
          doBlink(function() {
            setTimeout(function() {
              doBlink(scheduleNextBlink);
            }, 90);
          });
        } else if (roll < 0.25) {
          // Slow/lazy blink (Batman attitude)
          doSlowBlink(scheduleNextBlink);
        } else {
          // Normal blink
          doBlink(scheduleNextBlink);
        }
      }, delay);
    }

    // Kick off after a short natural delay
    setTimeout(scheduleNextBlink, 1200);
    // ──────────────────────────────────────────────────────────────

    function animate() {
      currentFactor += (targetFactor - currentFactor) * EASE;

      // Asymmetric clamping: more range looking up than down
      const rawDeg = currentFactor * MAX_ROTATE;
      const deg = Math.max(-3, Math.min(8, rawDeg));
      const offsetY = currentFactor * MAX_OFFSET;

      const transform =
        'rotate(' + deg.toFixed(3) + ',' + PIVOT_X + ',' + PIVOT_Y + ')';

      tracker.setAttribute('transform', transform);
      requestAnimationFrame(animate);
    }

    animate();
  })();
//
